teamsForPB = []
for team in teams['team']:
    region = team['region-name']
    line = [region]
    seed = 0
    for competitor in team['user']:
        seed = seed + pbs[competitor['wca-id']]
        line.append(competitor['name'])
    line.append(seed)
    teamsForPB.append(line)

teamsForPB.sort(key=lambda x: x[4])

teamRanking = dict([])
for team in teamsForPB:
    if team[0] not in teamRanking:
        teamRanking[team[0]] = 1
    else:
        teamRanking[team[0]] = teamRanking[team[0]] + 1
    team[0] = f'{team[0]} - {teamRanking[team[0]]}'

teamsForPB.sort(key=lambda x: x[0][-1])

